function searchMatrix(matrix, target) {
    let m = matrix.length;
    if (m === 0) return false;
    let n = matrix[0].length;

    let row = 0;
    let col = n - 1; // start from top-right

    while (row < m && col >= 0) {
        if (matrix[row][col] === target) {
            return true;
        } else if (matrix[row][col] > target) {
            col--; // move left
        } else {
            row++; // move down
        }
